const upsertPlatformConfig = `-- name: UpsertPlatformConfig :one
INSERT INTO platform_configs (
    config_key,
    config_value,
    scope_type,
    scope_id
) VALUES (
    $1, $2, $3, $4
) ON CONFLICT (config_key, scope_type, scope_id) DO UPDATE
SET config_value = EXCLUDED.config_value,
    updated_at = NOW()
RETURNING id, config_key, config_value, scope_type, scope_id, created_at, updated_at
`

type UpsertPlatformConfigParams struct {
	ConfigKey   string      `json:"config_key"`
	ConfigValue []byte      `json:"config_value"`
	ScopeType   string      `json:"scope_type"`
	ScopeID     pgtype.Int8 `json:"scope_id"`
}

func (q *Queries) UpsertPlatformConfig(ctx context.Context, arg UpsertPlatformConfigParams) (PlatformConfig, error) {
	row := q.db.QueryRow(ctx, upsertPlatformConfig,
		arg.ConfigKey,
		arg.ConfigValue,
		arg.ScopeType,
		arg.ScopeID,
	)
	var i PlatformConfig
	err := row.Scan(
		&i.ID,
		&i.ConfigKey,
		&i.ConfigValue,
		&i.ScopeType,
		&i.ScopeID,
		&i.CreatedAt,
		&i.UpdatedAt,
	)
	return i, err
}
